export const getListSeasonPlayersUrl = (year: number,
    params?: ListSeasonPlayersParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/seasons/${year}/players?${stringifiedParams}` : `/api/seasons/${year}/players`
}

